export async function seedExercises(): Promise<number> {
  const existing = await prisma.exercise.findMany({ select: { name: true } });
  const existingNames = new Set(existing.map((e) => e.name));
  const newExercises: SeededExercise[] = [];

  for (const ex of [...EXERCISES, ...EXTRA_EXERCISES]) {
    if (existingNames.has(ex.name)) continue;
    newExercises.push({
      name: ex.name,
      primaryMuscle: ex.primaryMuscle,
      secondaryMuscles: JSON.stringify(ex.secondaryMuscles),
      equipment: JSON.stringify(ex.equipment),
      difficulty: ex.difficulty,
      category: ex.category,
      tags: JSON.stringify(ex.tags),
      instructions: ex.instructions,
      met: ex.met ?? null,
      caloriesPerMin: ex.caloriesPerMin ?? null,
    });
  }

  if (newExercises.length > 0) {
    await prisma.exercise.createMany({ data: newExercises, skipDuplicates: true });
  }

  return newExercises.length;
}

if (import.meta.url === `file://${process.argv[1]}`) {
  seedExercises()
    .then((count) => {
      console.log(`Exercises seeded: ${count}`);
      return prisma.$disconnect();
    })
    .catch((e) => {
      console.error(e);
      return prisma.$disconnect().then(() => process.exit(1));
    });
}
